    fn enc_vcvtr_u32_f32(sd: u16, sm: u16) -> (u16, u16) {
        // Same as enc_vcvt_u32_f32 but opc3=0b1100 / t=0 (round per FPSCR).
        let vd = (sd >> 1) & 0xF;
        let d = sd & 1;
        let vm = (sm >> 1) & 0xF;
        let m = sm & 1;
        let hw0 = 0xEE00 | (1 << 7) | (d << 6) | (0b11 << 4) | 0b1100;
        let hw1 = ((vd << 12) | 0x0A00) | (1 << 6) | (m << 5) | vm;
        (hw0, hw1)
    }

